import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r,o as s,c as o,a as i,b as t,d as a,e as l}from"./app-754690a4.js";const h={},d=l('<h1 id="如何看待-xxx" tabindex="-1"><a class="header-anchor" href="#如何看待-xxx" aria-hidden="true">#</a> 如何看待 xxx</h1><div class="hint-container tip"><p class="hint-container-title">提示</p><p>本页不包含涉政内容</p></div><h2 id="如何看待大小城市中的人" tabindex="-1"><a class="header-anchor" href="#如何看待大小城市中的人" aria-hidden="true">#</a> 如何看待大小城市中的人</h2><ul><li>观点：折中说</li></ul><p>大城市的人有种精致的美，小城市的人有一种野性的美；从理性角度出发，两者都是美的。</p><h2 id="如何看待偏科" tabindex="-1"><a class="header-anchor" href="#如何看待偏科" aria-hidden="true">#</a> 如何看待偏科</h2><ul><li>观点：积极</li></ul><p>偏科的同学要么是天才，要么是明确知道自己的喜好并愿意为之付出多于常人的努力。在我看来，偏科的甚至比全能的更为优秀。（本观点不适用于全科天才或全科都非常喜欢的特例）</p><div style="text-align:right;font-style:italic;">——20230704</div><h2 id="专业与学校如何抉择" tabindex="-1"><a class="header-anchor" href="#专业与学校如何抉择" aria-hidden="true">#</a> 专业与学校如何抉择</h2><ul><li>观点：自由派</li></ul><p>虽然我本人是专业为重，但我的评价还是因人而异的。主要得看你对不喜欢的课程的强行接受程度。之前<strong>偏科</strong>严重的，那肯定以<strong>专业</strong>优先，毕竟专业不对，全是不喜欢的课程，根本学不下去。如果对自己的接受能力有足够自信，那还是学校优先，争取去了以后转专业。</p><p>还有不要想着一些专业名字听着很接近，感觉差不多，就。。。</p><div style="text-align:right;font-style:italic;">——20230630</div><h2 id="如何看待大学班级" tabindex="-1"><a class="header-anchor" href="#如何看待大学班级" aria-hidden="true">#</a> 如何看待大学班级</h2><ul><li>观点：<strong>灭绝派</strong>。</li></ul><p>首先对于我们这样一个各选各课的大学，班级的存在本身就是不必要的。</p><p>我读了两年大学，深知班级就是划分三六九等，作为部分同学与班导师的权利工具的存在。特权阶层（尤其是班导师）通过班级获得控制欲与满足感，有时候可能还有利益。借用信息化平台可以很轻松地发布通知，进行管理，而不必依赖班级本身的作用。我在此列出一些跟班级有关的破事：</p><ul><li>班导师（特指大二）以各种理由开线下线上班会，说些没有营养的话，浪费大家时间，满足自己的控制欲。</li><li>不民主的班级，作出集体决定时由班委讨论决定而不是公投。众所周知班委一般都是现充，他们作出的决定很大程度上会伤害到鼠鼠我。</li><li>财务管理不透明，班费去向不明。</li></ul><div style="text-align:right;font-style:italic;">——20230306</div><h2 id="如何看待关于-reactions-的讨论" tabindex="-1"><a class="header-anchor" href="#如何看待关于-reactions-的讨论" aria-hidden="true">#</a> 如何看待关于 reactions 的讨论</h2><p>如图，</p><div class="image40"><img alt="shortcut" src="https://cdn.staticaly.com/gh/lxl66566/lxl66566.github.io/images/gossip/consider/1.jpg"></div><p>观点：<strong>自由派</strong>。人们有表达自己观点的自由，频道不应该通过关闭部分 reactions 来限制这种自由。</p><div style="text-align:right;font-style:italic;">——20230219</div><h2 id="如何看待猫这种生物" tabindex="-1"><a class="header-anchor" href="#如何看待猫这种生物" aria-hidden="true">#</a> 如何看待猫这种生物</h2><p>我家养了两只猫，所以我应该对此问题具有发言权。我的态度是<strong>平均之下</strong>。论点如下：</p><ul><li>人喜欢猫大致是由于猫脸的拟婴态（引用论文）。而我有动机去克服这种生物本能。（ps.如果多看看猫的侧脸，也不会觉得有什么可爱）</li><li>家里养猫的目的是功能性宠物而非观赏性，平常是不被允许到室内活动的。而且它们从来不洗澡，不会出现吸猫等增加感情的互动，因此态度冷淡。</li><li>饿了就吵，到处搞破坏。白天睡晚上起，迟至 02:00，早至 05:20，就能被从睡梦中吵醒。</li><li>养猫会大幅增加弓形虫感染概率。</li><li>猫怕水，清洁主要靠舔，包括各种污物，自己的爪底等。</li></ul><p>因此我对猫没什么感情（不如养狗）。</p><div style="text-align:right;font-style:italic;">——20230205</div><h2 id="如何看待三体动画-电视剧" tabindex="-1"><a class="header-anchor" href="#如何看待三体动画-电视剧" aria-hidden="true">#</a> 如何看待三体动画/电视剧</h2><ul><li>观点：<strong>反对派</strong></li></ul><p>首先我没看过三体动画/电视剧。但就在半个月前我刚二刷完了三体原著。我的评价是<strong>人心比科幻更好看</strong>。但是这些精彩的点，我认为在中国的严格审查制度下很难体现在三体衍生作品中。同时，据说（来源知乎）三体（电视剧 ? 动画）有许多广告片段，充满了浓浓的资本气息；也不乏作为电视剧卖点的 cp 环节。因此我持反对态度。</p><p><s>而且我是幻想家，不需要视觉作品来为我构建画面。</s></p><div style="text-align:right;font-style:italic;">——20230117</div><h2 id="如何看待制作反-ai-的-license" tabindex="-1"><a class="header-anchor" href="#如何看待制作反-ai-的-license" aria-hidden="true">#</a> 如何看待制作反 AI 的 License</h2><ul><li>观点：激进派</li></ul>',37),c={href:"https://gpt.chatapi.art/",target:"_blank",rel:"noopener noreferrer"},p=l('<div style="text-align:right;font-style:italic;">——20221212</div><h2 id="如何看待竞技游戏匹配机制" tabindex="-1"><a class="header-anchor" href="#如何看待竞技游戏匹配机制" aria-hidden="true">#</a> 如何看待竞技游戏匹配机制</h2><p>绝大多数竞技游戏的匹配机制都是在你连赢/连输后给你匹配一些不正常的对手队友。</p><ul><li>观点：<strong>反对派</strong></li></ul><p>我对此只想给出两个字：<strong>傻*</strong>。更为恶心的是，（我的印象中）还没有游戏厂商或平台开源匹配算法。<s>开源是最好的文明！OSU 牛逼！</s></p><div style="text-align:right;font-style:italic;">——20221016</div><h2 id="如何看待-novelai-侵权" tabindex="-1"><a class="header-anchor" href="#如何看待-novelai-侵权" aria-hidden="true">#</a> 如何看待 NovelAI 侵权</h2><ul><li>观点：<strong>激进派</strong></li></ul><p>生成的图片被拿去干什么，取决于人而不是工具；而新技术总是会伴随着旧利益既得者的利益丧失，我认为是值得的。</p><div style="text-align:right;font-style:italic;">——20221016</div><h2 id="如何看待算法竞赛不使用最新语言特性" tabindex="-1"><a class="header-anchor" href="#如何看待算法竞赛不使用最新语言特性" aria-hidden="true">#</a> 如何看待算法竞赛不使用最新语言特性</h2>',11),g={href:"https://www.zhihu.com/question/30589288",target:"_blank",rel:"noopener noreferrer"},u=i("ul",null,[i("li",null,[t("观点："),i("strong",null,"激进派")])],-1),x=i("p",null,[t("作为高中时期参加 noip 和 csp-s 的 oier，在那些连 C++11 都不被允许的竞赛中，我只想说："),i("strong",null,"R N M"),t(". 编程领域需要更新更有活力的东西注入，算法竞赛也不该拘泥于手搓轮子，而是思维的构建。网上多数 OJ 都能爆杀 NOIP，蓝桥杯，ACM 等比赛。（多数 OJ 支持多种语言的最新特性）")],-1),f=i("div",{style:{"text-align":"right","font-style":"italic"}},"——20221016",-1);function _(v,y){const e=r("ExternalLinkIcon");return s(),o("div",null,[d,i("p",null,[t("就我最近几天使用 "),i("a",c,[t("ChatGPT"),a(e)]),t(" 来写代码的体验来说，AI 学习代码是件好事，应该大力支持。感觉这个 License 完全违背了开源精神。")]),p,i("p",null,[t("（观"),i("a",g,[t("此问题"),a(e)]),t("与回答有感）")]),u,x,f])}const N=n(h,[["render",_],["__file","consider.html.vue"]]);export{N as default};
